'use client';

import React from 'react';
import { Racquet } from '../../lib/types';

interface ComparisonTableProps {
  racquets: Racquet[];
  className?: string;
}

interface ComparisonRow {
  label: string;
  key: keyof Racquet;
  format?: (value: unknown) => string;
  category: 'basic' | 'physical' | 'performance';
}

const COMPARISON_ROWS: ComparisonRow[] = [
  // Basic Info
  { label: 'Brand', key: 'brand', category: 'basic' },
  { label: 'Model', key: 'model', category: 'basic' },
  { label: 'Review Count', key: 'review_count', format: (v) => v?.toString() || 'N/A', category: 'basic' },

  // Physical Specs
  { label: 'Weight (oz)', key: 'weight_oz', format: (v) => v ? `${v} oz` : 'N/A', category: 'physical' },
  { label: 'Head Size (sq in)', key: 'head_size_sq_in', format: (v) => v ? `${v} sq in` : 'N/A', category: 'physical' },
  { label: 'Length (in)', key: 'length_in', format: (v) => v ? `${v} in` : 'N/A', category: 'physical' },
  { label: 'Balance (pts)', key: 'balance_pts', format: (v) => (typeof v === 'number') ? `${v > 0 ? '+' : ''}${v} pts` : 'N/A', category: 'physical' },
  { label: 'Swingweight', key: 'swingweight', format: (v) => v?.toString() || 'N/A', category: 'physical' },
  { label: 'Flex Rating', key: 'flex', format: (v) => v?.toString() || 'N/A', category: 'physical' },
  { label: 'String Pattern', key: 'string_pattern', category: 'physical' },
  { label: 'Construction', key: 'construction', category: 'physical' },

  // Performance Ratings
  { label: 'Power', key: 'power_avg', format: (v) => (typeof v === 'number') ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
  { label: 'Control', key: 'control_avg', format: (v) => (typeof v === 'number') ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
  { label: 'Comfort', key: 'comfort_avg', format: (v) => (typeof v === 'number') ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
  { label: 'Maneuverability', key: 'maneuverability_avg', format: (v) => (typeof v === 'number') ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
  { label: 'Stability', key: 'stability_avg', format: (v) => (typeof v === 'number') ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
  { label: 'Serves', key: 'serves_avg', format: (v) => (typeof v === 'number') ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
  { label: 'Returns', key: 'returns_avg', format: (v) => (typeof v === 'number') ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
  { label: 'Groundstrokes', key: 'groundstrokes_avg', format: (v) => (typeof v === 'number') ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
  { label: 'Volleys', key: 'volleys_avg', format: (v) => (typeof v === 'number') ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
  { label: 'Touch/Feel', key: 'touch_feel_avg', format: (v) => (typeof v === 'number') ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
  { label: 'Overall', key: 'overall_avg', format: (v) => v ? `${v.toFixed(1)}/10` : 'N/A', category: 'performance' },
];

export function ComparisonTable({ racquets, className = '' }: ComparisonTableProps) {
  if (racquets.length === 0) {
    return (
      <div className={`text-center py-8 text-gray-500 ${className}`}>
        No racquets selected for comparison
      </div>
    );
  }

  const renderValue = (racquet: Racquet, row: ComparisonRow) => {
    const value = racquet[row.key];
    if (row.format) {
      return row.format(value);
    }
    return value?.toString() || 'N/A';
  };

  const getBestValue = (row: ComparisonRow) => {
    if (row.category !== 'performance') return null;

    const values = racquets
      .map(r => r[row.key] as number)
      .filter(v => v !== undefined);

    if (values.length === 0) return null;
    return Math.max(...values);
  };

  const isHighlighted = (racquet: Racquet, row: ComparisonRow) => {
    if (row.category !== 'performance') return false;

    const value = racquet[row.key] as number;
    const bestValue = getBestValue(row);

    return value !== undefined && bestValue !== null && Math.abs(value - bestValue) < 0.1;
  };

  const categoryLabels = {
    basic: 'Basic Information',
    physical: 'Physical Specifications',
    performance: 'Performance Ratings'
  };

  return (
    <div className={`overflow-x-auto ${className}`}>
      <table className="w-full border-collapse bg-white rounded-lg shadow-sm">
        <thead>
          <tr className="bg-gray-50">
            <th className="text-left p-4 font-medium text-gray-700 border-b">
              Specification
            </th>
            {racquets.map((racquet) => (
              <th
                key={racquet.id}
                className="text-left p-4 font-medium text-gray-700 border-b min-w-[200px]"
              >
                <div className="flex flex-col">
                  <span className="font-semibold">{racquet.brand}</span>
                  <span className="text-sm text-gray-500">{racquet.model}</span>
                </div>
              </th>
            ))}
          </tr>
        </thead>
        <tbody>
          {Object.entries(categoryLabels).map(([category, label]) => (
            <React.Fragment key={category}>
              <tr className="bg-gray-100">
                <td
                  colSpan={racquets.length + 1}
                  className="p-3 font-semibold text-gray-700 text-sm uppercase tracking-wide"
                >
                  {label}
                </td>
              </tr>
              {COMPARISON_ROWS.filter(row => row.category === category).map((row) => (
                <tr key={row.key} className="hover:bg-gray-50">
                  <td className="p-4 font-medium text-gray-700 border-b">
                    {row.label}
                  </td>
                  {racquets.map((racquet) => (
                    <td
                      key={racquet.id}
                      className={`p-4 border-b ${
                        isHighlighted(racquet, row)
                          ? 'bg-green-50 text-green-800 font-semibold'
                          : 'text-gray-600'
                      }`}
                    >
                      {renderValue(racquet, row)}
                    </td>
                  ))}
                </tr>
              ))}
            </React.Fragment>
          ))}
        </tbody>
      </table>

      <div className="mt-4 text-sm text-gray-500 flex items-center gap-2">
        <div className="w-4 h-4 bg-green-50 border border-green-200 rounded"></div>
        <span>Highest performance rating in category</span>
      </div>
    </div>
  );
}

'use client';

import React, { useState } from 'react';
import { Card } from '../ui/Card';
import { Button } from '../ui/Button';
import { Select } from '../ui/Select';
import { Input } from '../ui/Input';
import { Label } from '../ui/Label';
import { LoadingSpinner } from '../ui/LoadingSpinner';
import { RecommendationCard } from './RecommendationCard';
import { useRecommendations } from '../../lib/hooks/useRecommendations';
import { UserPreferences } from '../../lib/utils/recommendation-algorithm';
import { Racquet } from '../../lib/types';

interface RecommendationEngineProps {
  racquets: Racquet[];
  onCompareRacquet?: (racquet: Racquet) => void;
  onViewRacquetDetails?: (racquet: Racquet) => void;
  className?: string;
}

export function RecommendationEngine({
  racquets,
  onCompareRacquet,
  onViewRacquetDetails,
  className = ''
}: RecommendationEngineProps) {
  const [showPreferences, setShowPreferences] = useState(false);
  const [activeTab, setActiveTab] = useState<'primary' | 'alternatives' | 'budget'>('primary');

  const {
    recommendations,
    isLoading,
    error,
    userPreferences,
    updatePreferences,
    resetPreferences,
    hasRecommendations,
  } = useRecommendations(racquets);

  const handlePreferenceChange = (key: keyof UserPreferences, value: string | number) => {
    updatePreferences({ [key]: value });
  };

  const handleRangeChange = (key: keyof UserPreferences, index: number, value: number) => {
    const currentRange = userPreferences[key] as [number, number];
    const newRange: [number, number] = [...currentRange];
    newRange[index] = value;
    updatePreferences({ [key]: newRange });
  };

  const currentRecommendations = recommendations ? {
    primary: recommendations.primary_recommendations,
    alternatives: recommendations.alternative_recommendations,
    budget: recommendations.budget_alternatives,
  }[activeTab] || [] : [];

  return (
    <div className={`space-y-6 ${className}`}>
      {/* Header */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-2xl font-bold text-gray-900">
            Racquet Recommendations
          </h2>
          <p className="text-gray-600">
            Get personalized racquet suggestions based on your playing style
          </p>
        </div>
        <div className="flex gap-2">
          <Button
            variant="outline"
            onClick={() => setShowPreferences(!showPreferences)}
          >
            {showPreferences ? 'Hide' : 'Customize'} Preferences
          </Button>
          {hasRecommendations && (
            <Button
              variant="outline"
              onClick={resetPreferences}
            >
              Reset
            </Button>
          )}
        </div>
      </div>

      {/* Preferences Panel */}
      {showPreferences && (
        <Card className="p-6">
          <h3 className="text-lg font-semibold mb-4">Your Playing Preferences</h3>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            {/* Playing Style */}
            <div className="space-y-2">
              <Label htmlFor="playing-style">Playing Style</Label>
              <Select
                id="playing-style"
                value={userPreferences.playing_style}
                onValueChange={(value) => handlePreferenceChange('playing_style', value)}
              >
                <option value="baseline">Baseline Player</option>
                <option value="allcourt">All-Court Player</option>
                <option value="serve_volley">Serve & Volley</option>
                <option value="beginner">Beginner</option>
              </Select>
            </div>

            {/* Experience Level */}
            <div className="space-y-2">
              <Label htmlFor="experience">Experience Level</Label>
              <Select
                id="experience"
                value={userPreferences.experience_level}
                onValueChange={(value) => handlePreferenceChange('experience_level', value)}
              >
                <option value="beginner">Beginner</option>
                <option value="intermediate">Intermediate</option>
                <option value="advanced">Advanced</option>
                <option value="professional">Professional</option>
              </Select>
            </div>

            {/* Performance Priorities */}
            <div className="space-y-4">
              <Label>Performance Priorities (1-10)</Label>

              <div className="space-y-3">
                <div className="flex items-center justify-between">
                  <span className="text-sm font-medium">Power</span>
                  <div className="flex items-center gap-2">
                    <Input
                      type="range"
                      min="1"
                      max="10"
                      value={userPreferences.power_priority}
                      onChange={(e) => handlePreferenceChange('power_priority', parseInt(e.target.value))}
                      className="w-24"
                    />
                    <span className="text-sm w-6">{userPreferences.power_priority}</span>
                  </div>
                </div>

                <div className="flex items-center justify-between">
                  <span className="text-sm font-medium">Control</span>
                  <div className="flex items-center gap-2">
                    <Input
                      type="range"
                      min="1"
                      max="10"
                      value={userPreferences.control_priority}
                      onChange={(e) => handlePreferenceChange('control_priority', parseInt(e.target.value))}
                      className="w-24"
                    />
                    <span className="text-sm w-6">{userPreferences.control_priority}</span>
                  </div>
                </div>

                <div className="flex items-center justify-between">
                  <span className="text-sm font-medium">Comfort</span>
                  <div className="flex items-center gap-2">
                    <Input
                      type="range"
                      min="1"
                      max="10"
                      value={userPreferences.comfort_priority}
                      onChange={(e) => handlePreferenceChange('comfort_priority', parseInt(e.target.value))}
                      className="w-24"
                    />
                    <span className="text-sm w-6">{userPreferences.comfort_priority}</span>
                  </div>
                </div>

                <div className="flex items-center justify-between">
                  <span className="text-sm font-medium">Maneuverability</span>
                  <div className="flex items-center gap-2">
                    <Input
                      type="range"
                      min="1"
                      max="10"
                      value={userPreferences.maneuverability_priority}
                      onChange={(e) => handlePreferenceChange('maneuverability_priority', parseInt(e.target.value))}
                      className="w-24"
                    />
                    <span className="text-sm w-6">{userPreferences.maneuverability_priority}</span>
                  </div>
                </div>
              </div>
            </div>

            {/* Physical Preferences */}
            <div className="space-y-4">
              <Label>Physical Preferences</Label>

              <div className="space-y-3">
                <div>
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-sm font-medium">Weight Range (oz)</span>
                    <span className="text-sm text-gray-600">
                      {userPreferences.preferred_weight_range?.[0] || 9} - {userPreferences.preferred_weight_range?.[1] || 13}
                    </span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Input
                      type="range"
                      min="8"
                      max="14"
                      step="0.1"
                      value={userPreferences.preferred_weight_range?.[0] || 9}
                      onChange={(e) => handleRangeChange('preferred_weight_range', 0, parseFloat(e.target.value))}
                      className="flex-1"
                    />
                    <Input
                      type="range"
                      min="8"
                      max="14"
                      step="0.1"
                      value={userPreferences.preferred_weight_range?.[1] || 13}
                      onChange={(e) => handleRangeChange('preferred_weight_range', 1, parseFloat(e.target.value))}
                      className="flex-1"
                    />
                  </div>
                </div>

                <div>
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-sm font-medium">Head Size Range (sq in)</span>
                    <span className="text-sm text-gray-600">
                      {userPreferences.preferred_head_size_range?.[0] || 90} - {userPreferences.preferred_head_size_range?.[1] || 110}
                    </span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Input
                      type="range"
                      min="85"
                      max="120"
                      value={userPreferences.preferred_head_size_range?.[0] || 90}
                      onChange={(e) => handleRangeChange('preferred_head_size_range', 0, parseInt(e.target.value))}
                      className="flex-1"
                    />
                    <Input
                      type="range"
                      min="85"
                      max="120"
                      value={userPreferences.preferred_head_size_range?.[1] || 110}
                      onChange={(e) => handleRangeChange('preferred_head_size_range', 1, parseInt(e.target.value))}
                      className="flex-1"
                    />
                  </div>
                </div>
              </div>
            </div>
          </div>
        </Card>
      )}

      {/* Error State */}
      {error && (
        <Card className="p-4 border-red-200 bg-red-50">
          <p className="text-red-700">{error}</p>
        </Card>
      )}

      {/* Loading State */}
      {isLoading && (
        <Card className="p-8 flex items-center justify-center">
          <LoadingSpinner />
          <span className="ml-2 text-gray-600">Analyzing racquets...</span>
        </Card>
      )}

      {/* Recommendations */}
      {hasRecommendations && !isLoading && (
        <div className="space-y-4">
          {/* Tab Navigation */}
          <div className="flex border-b">
            <button
              onClick={() => setActiveTab('primary')}
              className={`px-4 py-2 font-medium text-sm border-b-2 ${
                activeTab === 'primary' 
                  ? 'border-blue-500 text-blue-600' 
                  : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            >
              Top Recommendations ({recommendations?.primary_recommendations.length || 0})
            </button>
            <button
              onClick={() => setActiveTab('alternatives')}
              className={`px-4 py-2 font-medium text-sm border-b-2 ${
                activeTab === 'alternatives' 
                  ? 'border-blue-500 text-blue-600' 
                  : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            >
              Alternatives ({recommendations?.alternative_recommendations.length || 0})
            </button>
            <button
              onClick={() => setActiveTab('budget')}
              className={`px-4 py-2 font-medium text-sm border-b-2 ${
                activeTab === 'budget' 
                  ? 'border-blue-500 text-blue-600' 
                  : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            >
              Budget Options ({recommendations?.budget_alternatives.length || 0})
            </button>
          </div>

          {/* Recommendations Grid */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
            {currentRecommendations.map((recommendation, index) => (
              <RecommendationCard
                key={`${recommendation.racquet.id}-${index}`}
                recommendation={recommendation}
                onCompare={onCompareRacquet}
                onViewDetails={onViewRacquetDetails}
                showAlternativeContext={activeTab !== 'primary'}
              />
            ))}
          </div>

          {currentRecommendations.length === 0 && (
            <Card className="p-8 text-center">
              <p className="text-gray-600">
                No {activeTab} recommendations found. Try adjusting your preferences.
              </p>
            </Card>
          )}
        </div>
      )}

      {/* Call to Action */}
      {!hasRecommendations && !isLoading && (
        <Card className="p-8 text-center">
          <h3 className="text-lg font-semibold mb-2">Get Personalized Recommendations</h3>
          <p className="text-gray-600 mb-4">
            Tell us about your playing style and preferences to get tailored racquet recommendations.
          </p>
          <Button 
            onClick={() => setShowPreferences(true)}
            variant="default"
          >
            Set Your Preferences
          </Button>
        </Card>
      )}
    </div>
  );
}

