                  <div className="flex items-center gap-2">
                    <Input
                      type="range"
                      min="1"
                      max="10"
                      value={userPreferences.control_priority}
                      onChange={(e) => handlePreferenceChange('control_priority', parseInt(e.target.value))}
                      className="w-24"
                    />
                    <span className="text-sm w-6">{userPreferences.control_priority}</span>
                  </div>
                </div>

                <div className="flex items-center justify-between">
                  <span className="text-sm font-medium">Comfort</span>
                  <div className="flex items-center gap-2">
                    <Input
                      type="range"
                      min="1"
                      max="10"
                      value={userPreferences.comfort_priority}
                      onChange={(e) => handlePreferenceChange('comfort_priority', parseInt(e.target.value))}
                      className="w-24"
                    />
                    <span className="text-sm w-6">{userPreferences.comfort_priority}</span>
                  </div>
                </div>

                <div className="flex items-center justify-between">
                  <span className="text-sm font-medium">Maneuverability</span>
                  <div className="flex items-center gap-2">
                    <Input
                      type="range"
                      min="1"
                      max="10"
                      value={userPreferences.maneuverability_priority}
                      onChange={(e) => handlePreferenceChange('maneuverability_priority', parseInt(e.target.value))}
                      className="w-24"
                    />
                    <span className="text-sm w-6">{userPreferences.maneuverability_priority}</span>
                  </div>
                </div>
              </div>
            </div>

            {/* Physical Preferences */}
            <div className="space-y-4">
              <Label>Physical Preferences</Label>

              <div className="space-y-3">
                <div>
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-sm font-medium">Weight Range (oz)</span>
                    <span className="text-sm text-gray-600">
                      {userPreferences.preferred_weight_range?.[0] || 9} - {userPreferences.preferred_weight_range?.[1] || 13}
                    </span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Input
                      type="range"
                      min="8"
                      max="14"
                      step="0.1"
                      value={userPreferences.preferred_weight_range?.[0] || 9}
                      onChange={(e) => handleRangeChange('preferred_weight_range', 0, parseFloat(e.target.value))}
                      className="flex-1"
                    />
                    <Input
                      type="range"
                      min="8"
                      max="14"
                      step="0.1"
                      value={userPreferences.preferred_weight_range?.[1] || 13}
                      onChange={(e) => handleRangeChange('preferred_weight_range', 1, parseFloat(e.target.value))}
                      className="flex-1"
                    />
                  </div>
                </div>

                <div>
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-sm font-medium">Head Size Range (sq in)</span>
                    <span className="text-sm text-gray-600">
                      {userPreferences.preferred_head_size_range?.[0] || 90} - {userPreferences.preferred_head_size_range?.[1] || 110}
                    </span>
                  </div>
                  <div className="flex items-center gap-2">
                    <Input
                      type="range"
                      min="85"
                      max="120"
                      value={userPreferences.preferred_head_size_range?.[0] || 90}
                      onChange={(e) => handleRangeChange('preferred_head_size_range', 0, parseInt(e.target.value))}
                      className="flex-1"
                    />
                    <Input
                      type="range"
                      min="85"
                      max="120"
                      value={userPreferences.preferred_head_size_range?.[1] || 110}
                      onChange={(e) => handleRangeChange('preferred_head_size_range', 1, parseInt(e.target.value))}
                      className="flex-1"
                    />
                  </div>
                </div>
              </div>
            </div>
          </div>
        </Card>
      )}

      {/* Error State */}
      {error && (
        <Card className="p-4 border-red-200 bg-red-50">
          <p className="text-red-700">{error}</p>
        </Card>
      )}

      {/* Loading State */}
      {isLoading && (
        <Card className="p-8 flex items-center justify-center">
          <LoadingSpinner />
          <span className="ml-2 text-gray-600">Analyzing racquets...</span>
        </Card>
      )}

      {/* Recommendations */}
      {hasRecommendations && !isLoading && (
        <div className="space-y-4">
          {/* Tab Navigation */}
          <div className="flex border-b">
            <button
              onClick={() => setActiveTab('primary')}
              className={`px-4 py-2 font-medium text-sm border-b-2 ${
                activeTab === 'primary' 
                  ? 'border-blue-500 text-blue-600' 
                  : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            >
              Top Recommendations ({recommendations?.primary_recommendations.length || 0})
            </button>
            <button
              onClick={() => setActiveTab('alternatives')}
              className={`px-4 py-2 font-medium text-sm border-b-2 ${
                activeTab === 'alternatives' 
                  ? 'border-blue-500 text-blue-600' 
                  : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            >
              Alternatives ({recommendations?.alternative_recommendations.length || 0})
            </button>
            <button
              onClick={() => setActiveTab('budget')}
              className={`px-4 py-2 font-medium text-sm border-b-2 ${
                activeTab === 'budget' 
                  ? 'border-blue-500 text-blue-600' 
                  : 'border-transparent text-gray-500 hover:text-gray-700'
              }`}
            >
              Budget Options ({recommendations?.budget_alternatives.length || 0})
            </button>
          </div>

          {/* Recommendations Grid */}
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4">
            {currentRecommendations.map((recommendation, index) => (
              <RecommendationCard
                key={`${recommendation.racquet.id}-${index}`}
                recommendation={recommendation}
                onCompare={onCompareRacquet}
                onViewDetails={onViewRacquetDetails}
                showAlternativeContext={activeTab !== 'primary'}
              />
            ))}
          </div>

          {currentRecommendations.length === 0 && (
            <Card className="p-8 text-center">
              <p className="text-gray-600">
                No {activeTab} recommendations found. Try adjusting your preferences.
              </p>
            </Card>
          )}
        </div>
      )}

      {/* Call to Action */}
      {!hasRecommendations && !isLoading && (
        <Card className="p-8 text-center">
          <h3 className="text-lg font-semibold mb-2">Get Personalized Recommendations</h3>
          <p className="text-gray-600 mb-4">
            Tell us about your playing style and preferences to get tailored racquet recommendations.
          </p>
          <Button 
            onClick={() => setShowPreferences(true)}
            variant="default"
          >
            Set Your Preferences
          </Button>
        </Card>
      )}
    </div>
  );
}

