interface RacquetPoints3DProps {
  racquets: Racquet[];
  positions: PCACoordinates[];
  selectedRacquet?: string | null;
  hoveredRacquet?: string | null;
  onRacquetClick?: (racquet: Racquet) => void;
  onRacquetHover?: (racquet: Racquet | null) => void;
  colorBy?: keyof Racquet;
  scale?: number;
}

export function RacquetPoints3D({
  racquets,
  positions,
  selectedRacquet,
  hoveredRacquet,
  onRacquetClick,
  onRacquetHover,
  colorBy = 'brand',
  scale = 1
}: RacquetPoints3DProps) {

  // Generate colors based on colorBy property
  const colorMap = useMemo(() => {
    const uniqueValues = Array.from(new Set(racquets.map(r => r[colorBy])));
    const colors = [
      '#3b82f6', '#ef4444', '#10b981', '#f59e0b', '#8b5cf6',
      '#ec4899', '#06b6d4', '#84cc16', '#f97316', '#6366f1'
    ];

    const map = new Map<unknown, string>();
    uniqueValues.forEach((value, index) => {
      map.set(value, colors[index % colors.length]);
    });

    return map;
  }, [racquets, colorBy]);

  // Calculate bounds for scaling
  const bounds = useMemo(() => {
    if (positions.length === 0) return { min: -1, max: 1 };

    const allValues = positions.flatMap(p => [p.x, p.y, p.z || 0]);
    const min = Math.min(...allValues);
    const max = Math.max(...allValues);
    const range = max - min;

    return { min, max, range };
  }, [positions]);

  // Scale positions to fit in scene
  const scaledPositions = useMemo(() => {
    if (bounds.range === 0) return positions;

    const scaleMultiplier = 8; // Fit within -8 to 8 range

    return positions.map(pos => ({
      x: ((pos.x - bounds.min) / bounds.range - 0.5) * scaleMultiplier,
      y: ((pos.y - bounds.min) / bounds.range - 0.5) * scaleMultiplier,
      z: pos.z ? ((pos.z - bounds.min) / bounds.range - 0.5) * scaleMultiplier : 0
    }));
  }, [positions, bounds]);

  const handleRacquetClick = useCallback((racquet: Racquet) => {
    onRacquetClick?.(racquet);
  }, [onRacquetClick]);

  const handleRacquetHover = useCallback((racquet: Racquet | null) => {
    onRacquetHover?.(racquet);
  }, [onRacquetHover]);

  return (
    <group>
      {racquets.map((racquet, index) => {
        if (index >= scaledPositions.length) return null;

        const position = scaledPositions[index];
        const color = colorMap.get(racquet[colorBy]) || '#3b82f6';

        return (
          <RacquetPoint3D
            key={racquet.id}
            racquet={racquet}
            position={position}
            isSelected={selectedRacquet === racquet.id}
            isHovered={hoveredRacquet === racquet.id}
            onClick={handleRacquetClick}
            onHover={handleRacquetHover}
            scale={scale}
            color={color}
          />
        );
      })}
    </group>
  );
}

