'use client';

import { Suspense, useRef, useEffect } from 'react';
import { Canvas, useFrame, extend, useThree } from '@react-three/fiber';
import { OrbitControls, Grid, Text, Html } from '@react-three/drei';
import { LoadingSpinner } from '@/components/ui/LoadingSpinner';
import * as THREE from 'three';

extend({ OrbitControls });

interface ThreeSceneProps {
  children: React.ReactNode;
  className?: string;
  showGrid?: boolean;
  showAxes?: boolean;
  cameraPosition?: [number, number, number];
  onCameraChange?: (position: THREE.Vector3, target: THREE.Vector3) => void;
}

function SceneGrid({ visible = true }: { visible?: boolean }) {
  if (!visible) return null;

  return (
    <Grid
      args={[20, 20]}
      position={[0, -5, 0]}
      cellSize={1}
      cellThickness={0.5}
      cellColor="#6b7280"
      sectionSize={5}
      sectionThickness={1}
      sectionColor="#9ca3af"
      fadeDistance={50}
      fadeStrength={1}
      infiniteGrid
    />
  );
}

function AxisHelper({ visible = true }: { visible?: boolean }) {
  if (!visible) return null;

  return (
    <group>
      {/* X-axis - Red */}
      <line>
        <bufferGeometry>
          <bufferAttribute
            attach="attributes-position"
            array={new Float32Array([-10, 0, 0, 10, 0, 0])}
            count={2}
            itemSize={3}
          />
        </bufferGeometry>
        <lineBasicMaterial color="#ef4444" />
      </line>

      {/* Y-axis - Green */}
      <line>
        <bufferGeometry>
          <bufferAttribute
            attach="attributes-position"
            array={new Float32Array([0, -10, 0, 0, 10, 0])}
            count={2}
            itemSize={3}
          />
        </bufferGeometry>
        <lineBasicMaterial color="#22c55e" />
      </line>

      {/* Z-axis - Blue */}
      <line>
        <bufferGeometry>
          <bufferAttribute
            attach="attributes-position"
            array={new Float32Array([0, 0, -10, 0, 0, 10])}
            count={2}
            itemSize={3}
          />
        </bufferGeometry>
        <lineBasicMaterial color="#3b82f6" />
      </line>

      {/* Axis labels */}
      <Text
        position={[11, 0, 0]}
        fontSize={0.8}
        color="#ef4444"
        anchorX="center"
        anchorY="middle"
      >
        X
      </Text>
      <Text
        position={[0, 11, 0]}
        fontSize={0.8}
        color="#22c55e"
        anchorX="center"
        anchorY="middle"
      >
        Y
      </Text>
      <Text
        position={[0, 0, 11]}
        fontSize={0.8}
        color="#3b82f6"
        anchorX="center"
        anchorY="middle"
      >
        Z
      </Text>
    </group>
  );
}

function CameraController({ 
  position = [10, 10, 10], 
  onCameraChange 
}: { 
  position?: [number, number, number];
  onCameraChange?: (position: THREE.Vector3, target: THREE.Vector3) => void;
}) {
  const controlsRef = useRef<unknown>();
  const { camera } = useThree();

  useEffect(() => {
    if (camera) {
      camera.position.set(...position);
      camera.lookAt(0, 0, 0);
    }
  }, [camera, position]);

  useFrame(() => {
    if (controlsRef.current && onCameraChange) {
      const controls = controlsRef.current;
      onCameraChange(camera.position, controls.target);
    }
  });

  return (
    <OrbitControls
      ref={controlsRef}
      enablePan={true}
      enableZoom={true}
      enableRotate={true}
      dampingFactor={0.05}
      enableDamping={true}
      maxDistance={50}
      minDistance={5}
      maxPolarAngle={Math.PI}
      minPolarAngle={0}
      autoRotate={false}
      autoRotateSpeed={0.5}
      target={[0, 0, 0]}
    />
  );
}

function Lighting() {
  return (
    <>
      <ambientLight intensity={0.4} />
      <directionalLight
        position={[10, 10, 10]}
        intensity={1}
        castShadow
        shadow-mapSize-width={2048}
        shadow-mapSize-height={2048}
        shadow-camera-far={50}
        shadow-camera-left={-10}
        shadow-camera-right={10}
        shadow-camera-top={10}
        shadow-camera-bottom={-10}
      />
      <directionalLight
        position={[-10, -10, -10]}
        intensity={0.2}
      />
    </>
  );
}

function LoadingFallback() {
  return (
    <div className="flex items-center justify-center h-full">
      <LoadingSpinner size="lg" />
    </div>
  );
}

export function ThreeScene({
  children,
  className = '',
  showGrid = true,
  showAxes = true,
  cameraPosition = [10, 10, 10],
  onCameraChange
}: ThreeSceneProps) {
  return (
    <div className={`w-full h-full ${className}`}>
      <Canvas
        shadows
        camera={{ 
          fov: 60, 
          near: 0.1, 
          far: 200,
          position: cameraPosition 
        }}
        gl={{ 
          antialias: true,
          alpha: true,
          powerPreference: "high-performance"
        }}
        dpr={[1, 2]}
        style={{
          background: 'transparent'
        }}
      >
        <Suspense 
          fallback={
            <Html center>
              <LoadingFallback />
            </Html>
          }
        >
          <Lighting />
          <SceneGrid visible={showGrid} />
          <AxisHelper visible={showAxes} />
          <CameraController 
            position={cameraPosition} 
            onCameraChange={onCameraChange}
          />
          {children}
        </Suspense>
      </Canvas>
    </div>
  );
}

