'use client';

import { useState, useEffect, useCallback, useMemo } from 'react';
import { useRouter, useSearchParams } from 'next/navigation';
import { Racquet, Brand } from '@/lib/types';

interface FilterState {
  brands: string[];
  weight_range: [number, number];
  head_size_range: [number, number];
  power_range: [number, number];
  control_range: [number, number];
  comfort_range: [number, number];
  search_query: string;
}

interface UseRacquetFiltersProps {
  racquets: Racquet[];
  brands: Brand[];
  persistToURL?: boolean;
}

interface UseRacquetFiltersReturn {
  filters: FilterState;
  filteredRacquets: Racquet[];
  setFilters: (filters: Partial<FilterState>) => void;
  resetFilters: () => void;
  filterCounts: {
    total: number;
    filtered: number;
  };
  ranges: {
    weight: [number, number];
    head_size: [number, number];
    power: [number, number];
    control: [number, number];
    comfort: [number, number];
  };
}

export function useRacquetFilters({
  racquets,
  brands,
  persistToURL = false,
}: UseRacquetFiltersProps): UseRacquetFiltersReturn {
  const router = useRouter();
  const searchParams = useSearchParams();

  // Calculate data ranges
  const ranges = useMemo(() => {
    const weights = racquets.map(r => r.weight_oz).filter(Boolean) as number[];
    const headSizes = racquets.map(r => r.head_size_sq_in).filter(Boolean) as number[];
    const powers = racquets.map(r => r.power_avg).filter(Boolean) as number[];
    const controls = racquets.map(r => r.control_avg).filter(Boolean) as number[];
    const comforts = racquets.map(r => r.comfort_avg).filter(Boolean) as number[];

    return {
      weight: [Math.min(...weights), Math.max(...weights)] as [number, number],
      head_size: [Math.min(...headSizes), Math.max(...headSizes)] as [number, number],
      power: [Math.min(...powers), Math.max(...powers)] as [number, number],
      control: [Math.min(...controls), Math.max(...controls)] as [number, number],
      comfort: [Math.min(...comforts), Math.max(...comforts)] as [number, number],
    };
  }, [racquets]);

  // Initialize filters from URL params or defaults
  const getInitialFilters = useCallback((): FilterState => {
    if (persistToURL && searchParams) {
      const brandsParam = searchParams.get('brands');
      const weightParam = searchParams.get('weight');
      const headSizeParam = searchParams.get('head_size');
      const powerParam = searchParams.get('power');
      const controlParam = searchParams.get('control');
      const comfortParam = searchParams.get('comfort');
      const searchParam = searchParams.get('search');

      return {
        brands: brandsParam ? brandsParam.split(',') : [],
        weight_range: weightParam ? JSON.parse(weightParam) : ranges.weight,
        head_size_range: headSizeParam ? JSON.parse(headSizeParam) : ranges.head_size,
        power_range: powerParam ? JSON.parse(powerParam) : ranges.power,
        control_range: controlParam ? JSON.parse(controlParam) : ranges.control,
        comfort_range: comfortParam ? JSON.parse(comfortParam) : ranges.comfort,
        search_query: searchParam || '',
      };
    }

    return {
      brands: [],
      weight_range: ranges.weight,
      head_size_range: ranges.head_size,
      power_range: ranges.power,
      control_range: ranges.control,
      comfort_range: ranges.comfort,
      search_query: '',
    };
  }, [persistToURL, searchParams, ranges]);

  const [filters, setFiltersState] = useState<FilterState>(getInitialFilters);

  // Update URL when filters change
  useEffect(() => {
    if (!persistToURL) return;

    const params = new URLSearchParams();

    if (filters.brands.length > 0) {
      params.set('brands', filters.brands.join(','));
    }
    if (JSON.stringify(filters.weight_range) !== JSON.stringify(ranges.weight)) {
      params.set('weight', JSON.stringify(filters.weight_range));
    }
    if (JSON.stringify(filters.head_size_range) !== JSON.stringify(ranges.head_size)) {
      params.set('head_size', JSON.stringify(filters.head_size_range));
    }
    if (JSON.stringify(filters.power_range) !== JSON.stringify(ranges.power)) {
      params.set('power', JSON.stringify(filters.power_range));
    }
    if (JSON.stringify(filters.control_range) !== JSON.stringify(ranges.control)) {
      params.set('control', JSON.stringify(filters.control_range));
    }
    if (JSON.stringify(filters.comfort_range) !== JSON.stringify(ranges.comfort)) {
      params.set('comfort', JSON.stringify(filters.comfort_range));
    }
    if (filters.search_query) {
      params.set('search', filters.search_query);
    }

    const newUrl = params.toString() ? `?${params.toString()}` : '';
    router.push(newUrl, { scroll: false });
  }, [filters, ranges, persistToURL, router]);

  // Filter racquets based on current filters
  const filteredRacquets = useMemo(() => {
    return racquets.filter(racquet => {
      // Brand filter
      if (filters.brands.length > 0 && !filters.brands.includes(racquet.brand.toLowerCase().replace(/\s+/g, '-'))) {
        return false;
      }

      // Weight filter
      if (racquet.weight_oz && 
          (racquet.weight_oz < filters.weight_range[0] || racquet.weight_oz > filters.weight_range[1])) {
        return false;
      }

      // Head size filter
      if (racquet.head_size_sq_in && 
          (racquet.head_size_sq_in < filters.head_size_range[0] || racquet.head_size_sq_in > filters.head_size_range[1])) {
        return false;
      }

      // Power filter
      if (racquet.power_avg && 
          (racquet.power_avg < filters.power_range[0] || racquet.power_avg > filters.power_range[1])) {
        return false;
      }

      // Control filter
      if (racquet.control_avg && 
          (racquet.control_avg < filters.control_range[0] || racquet.control_avg > filters.control_range[1])) {
        return false;
      }

      // Comfort filter
      if (racquet.comfort_avg && 
          (racquet.comfort_avg < filters.comfort_range[0] || racquet.comfort_avg > filters.comfort_range[1])) {
        return false;
      }

      // Search filter
      if (filters.search_query) {
        const searchLower = filters.search_query.toLowerCase();
        const searchableText = `${racquet.model} ${racquet.brand} ${racquet.material}`.toLowerCase();
        if (!searchableText.includes(searchLower)) {
          return false;
        }
      }

      return true;
    });
  }, [racquets, filters]);

  // Update filters function
  const setFilters = useCallback((newFilters: Partial<FilterState>) => {
    setFiltersState(prev => ({
      ...prev,
      ...newFilters,
    }));
  }, []);

  // Reset filters function
  const resetFilters = useCallback(() => {
    setFiltersState({
      brands: [],
      weight_range: ranges.weight,
      head_size_range: ranges.head_size,
      power_range: ranges.power,
      control_range: ranges.control,
      comfort_range: ranges.comfort,
      search_query: '',
    });
  }, [ranges]);

  // Filter counts
  const filterCounts = useMemo(() => ({
    total: racquets.length,
    filtered: filteredRacquets.length,
  }), [racquets.length, filteredRacquets.length]);

  return {
    filters,
    filteredRacquets,
    setFilters,
    resetFilters,
    filterCounts,
    ranges,
  };
}

