'use client';

import React, { useState } from 'react';
import { Racquet } from '../../lib/types';
import { useAnalytics } from '../../lib/hooks/useAnalytics';
import { StatsCard } from './StatsCard';
import { TrendChart } from './TrendChart';
import { Card } from '../ui/Card';
import { Button } from '../ui/Button';
import { Select } from '../ui/Select';
import { LoadingSpinner } from '../ui/LoadingSpinner';

export interface AnalyticsDashboardProps {
  racquets: Racquet[];
  className?: string;
}

export const AnalyticsDashboard: React.FC<AnalyticsDashboardProps> = ({
  racquets,
  className = ''
}) => {
  const [activeTab, setActiveTab] = useState<'performance' | 'physical' | 'brands' | 'quality'>('performance');

  const {
    performanceStats,
    physicalStats,
    brandAnalytics,
    dataQuality,
    isLoading,
    error,
    filters,
    updateFilters,
    resetFilters,
    toggleBrand,
    getBrandComparison,
    exportData,
    hasData
  } = useAnalytics({ racquets });

  if (isLoading) {
    return (
      <div className={`flex items-center justify-center p-12 ${className}`}>
        <LoadingSpinner size="lg" />
      </div>
    );
  }

  if (error || !hasData) {
    return (
      <Card className={className}>
        <div className="p-8 text-center">
          <h3 className="text-lg font-semibold text-gray-900 mb-2">
            No Analytics Data Available
          </h3>
          <p className="text-gray-600 mb-4">
            {error || 'No racquets match the current filters'}
          </p>
          {filters.selectedBrands.length > 0 && (
            <Button onClick={resetFilters} variant="outline">
              Clear Filters
            </Button>
          )}
        </div>
      </Card>
    );
  }

  const tabs = [
    { id: 'performance', label: 'Performance', icon: '📊' },
    { id: 'physical', label: 'Physical Specs', icon: '🏸' },
    { id: 'brands', label: 'Brand Analysis', icon: '🏷️' },
    { id: 'quality', label: 'Data Quality', icon: '📈' }
  ] as const;

  const handleSortChange = (value: string) => {
    const [sortBy, sortOrder] = value.split('-');
    updateFilters({
      sortBy: sortBy as 'count' | 'rating' | 'name',
      sortOrder: sortOrder as 'asc' | 'desc'
    });
  };

  const renderPerformanceTab = () => (
    <div className="space-y-6">
      {/* Performance Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {performanceStats.map((stat, index) => (
          <StatsCard
            key={stat.category}
            title={stat.category}
            stats={stat.stats}
            unit=""
            showPercentiles={false}
            colorScheme={
              index % 5 === 0 ? 'blue' :
              index % 5 === 1 ? 'green' :
              index % 5 === 2 ? 'purple' :
              index % 5 === 3 ? 'orange' : 'red'
            }
          />
        ))}
      </div>

      {/* Performance Trends */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <TrendChart
          title="Overall Rating by Brand"
          data={getBrandComparison('power')}
          valueLabel="Average Rating"
          unit="/10"
          colorScheme="blue"
          showCount={true}
        />
        <TrendChart
          title="Power vs Control Balance"
          data={brandAnalytics.map(brand => ({
            brand: brand.brand,
            value: brand.performanceProfile.power - brand.performanceProfile.control,
            count: brand.count
          }))}
          valueLabel="Power - Control"
          unit=""
          colorScheme="purple"
          showCount={true}
        />
      </div>
    </div>
  );

  const renderPhysicalTab = () => (
    <div className="space-y-6">
      {/* Physical Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {physicalStats.map((stat, index) => (
          <StatsCard
            key={stat.category}
            title={stat.category}
            stats={stat.stats}
            unit={
              stat.category.includes('Weight') ? ' oz' :
              stat.category.includes('Head Size') ? ' sq in' :
              stat.category.includes('Length') ? '"' : ''
            }
            showPercentiles={true}
            colorScheme={
              index % 5 === 0 ? 'green' :
              index % 5 === 1 ? 'blue' :
              index % 5 === 2 ? 'orange' :
              index % 5 === 3 ? 'purple' : 'red'
            }
          />
        ))}
      </div>

      {/* Physical Specification Trends */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <TrendChart
          title="Average Weight by Brand"
          data={brandAnalytics.map(brand => ({
            brand: brand.brand,
            value: brand.avgWeight,
            count: brand.count
          }))}
          valueLabel="Weight"
          unit=" oz"
          colorScheme="green"
          showCount={true}
        />
        <TrendChart
          title="Average Head Size by Brand"
          data={brandAnalytics.map(brand => ({
            brand: brand.brand,
            value: brand.avgHeadSize,
            count: brand.count
          }))}
          valueLabel="Head Size"
          unit=" sq in"
          colorScheme="orange"
          showCount={true}
        />
      </div>
    </div>
  );

  const renderBrandsTab = () => (
    <div className="space-y-6">
      {/* Brand Control Panel */}
      <Card className="bg-gray-50 border-gray-200">
        <div className="p-4">
          <div className="flex flex-wrap items-center gap-4">
            <div className="flex-1 min-w-48">
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Sort Brands By
              </label>
              <Select
                value={`${filters.sortBy}-${filters.sortOrder}`}
                onValueChange={handleSortChange}
                className="w-full"
              >
                <option value="count-desc">Most Racquets</option>
                <option value="count-asc">Fewest Racquets</option>
                <option value="rating-desc">Highest Rating</option>
                <option value="rating-asc">Lowest Rating</option>
                <option value="name-asc">Name A-Z</option>
                <option value="name-desc">Name Z-A</option>
              </Select>
            </div>

            <div className="flex items-end gap-2">
              <Button onClick={resetFilters} variant="outline" size="sm">
                Reset Filters
              </Button>
              <Button onClick={exportData} variant="default" size="sm">
                Export Data
              </Button>
            </div>
          </div>
        </div>
      </Card>

      {/* Brand Analytics Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {brandAnalytics.slice(0, 12).map((brand, index) => (
          <Card 
            key={brand.brand}
            className={`cursor-pointer transition-all duration-200 ${
              filters.selectedBrands.includes(brand.brand)
                ? 'bg-blue-50 border-blue-300 shadow-md'
                : 'hover:shadow-md hover:border-gray-300'
            }`}
            onClick={() => toggleBrand(brand.brand)}
          >
            <div className="p-4">
              <div className="flex items-center justify-between mb-3">
                <h3 className="font-semibold text-gray-900 truncate">
                  {brand.brand}
                </h3>
                <span className="text-sm text-gray-500 bg-gray-100 px-2 py-1 rounded-full">
                  {brand.count} racquets
                </span>
              </div>

              <div className="grid grid-cols-2 gap-3 text-sm">
                <div>
                  <div className="font-medium text-gray-900">
                    {brand.avgRating.toFixed(1)}/10
                  </div>
                  <div className="text-gray-500">Avg Rating</div>
                </div>
                <div>
                  <div className="font-medium text-gray-900">
                    {brand.avgWeight.toFixed(1)} oz
                  </div>
                  <div className="text-gray-500">Avg Weight</div>
                </div>
              </div>

              <div className="mt-3 pt-3 border-t border-gray-200">
                <div className="flex justify-between text-xs text-gray-600">
                  <span>Power: {brand.performanceProfile.power.toFixed(1)}</span>
                  <span>Control: {brand.performanceProfile.control.toFixed(1)}</span>
                </div>
              </div>
            </div>
          </Card>
        ))}
      </div>

      {/* Brand Comparison Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <TrendChart
          title="Brand Market Share"
          data={brandAnalytics.map(brand => ({
            brand: brand.brand,
            value: brand.count,
            count: brand.count
          }))}
          valueLabel="Racquet Count"
          unit=""
          colorScheme="blue"
          showCount={false}
        />
        <TrendChart
          title="Average Rating by Brand"
          data={brandAnalytics.map(brand => ({
            brand: brand.brand,
            value: brand.avgRating,
            count: brand.count
          }))}
          valueLabel="Rating"
          unit="/10"
          colorScheme="green"
          showCount={true}
        />
      </div>
    </div>
  );

  const renderQualityTab = () => (
    <div className="space-y-6">
      {/* Data Quality Overview */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <Card className="bg-blue-50 border-blue-200">
          <div className="p-6 text-center">
            <div className="text-3xl font-bold text-blue-900 mb-2">
              {dataQuality.totalRacquets}
            </div>
            <div className="text-sm text-blue-600">Total Racquets</div>
