            <div className="text-3xl font-bold text-green-900 mb-2">
              {dataQuality.totalReviews.toLocaleString()}
            </div>
            <div className="text-sm text-green-600">Total Reviews</div>
          </div>
        </Card>

        <Card className="bg-purple-50 border-purple-200">
          <div className="p-6 text-center">
            <div className="text-3xl font-bold text-purple-900 mb-2">
              {dataQuality.averageReviewsPerRacquet}
            </div>
            <div className="text-sm text-purple-600">Avg Reviews/Racquet</div>
          </div>
        </Card>
      </div>

      {/* Data Completeness */}
      <Card>
        <div className="p-6">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">
            Data Completeness
          </h3>

          <div className="space-y-4">
            <div>
              <div className="flex justify-between items-center mb-2">
                <span className="text-sm font-medium text-gray-700">
                  Physical Specifications
                </span>
                <span className="text-sm text-gray-600">
                  {dataQuality.completenessScores.physicalSpecs}%
                </span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div 
                  className="bg-blue-500 h-2 rounded-full transition-all duration-300"
