            </div>

            <div>
              <div className="flex justify-between items-center mb-2">
                <span className="text-sm font-medium text-gray-700">
                  Performance Ratings
                </span>
                <span className="text-sm text-gray-600">
                  {dataQuality.completenessScores.performanceRatings}%
                </span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div 
                  className="bg-green-500 h-2 rounded-full transition-all duration-300"
                  style={{ width: `${dataQuality.completenessScores.performanceRatings}%` }}
                />
              </div>
            </div>

            <div>
              <div className="flex justify-between items-center mb-2">
                <span className="text-sm font-medium text-gray-700">
                  Overall Completeness
                </span>
                <span className="text-sm text-gray-600">
                  {dataQuality.completenessScores.overall}%
                </span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div 
                  className="bg-purple-500 h-2 rounded-full transition-all duration-300"
                  style={{ width: `${dataQuality.completenessScores.overall}%` }}
                />
              </div>
            </div>
          </div>
        </div>
      </Card>

      {/* Distribution Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <TrendChart
          title="Weight Distribution"
          data={dataQuality.dataDistribution.weightRanges.map(range => ({
            brand: range.range,
            value: range.percentage,
            count: range.count
          }))}
          valueLabel="Percentage"
          unit="%"
          colorScheme="orange"
          showCount={true}
          maxBars={8}
        />
        <TrendChart
          title="Head Size Distribution"
          data={dataQuality.dataDistribution.headSizeRanges.map(range => ({
            brand: range.range,
            value: range.percentage,
            count: range.count
