import { NextRequest } from 'next/server';
import { GET } from '@/app/api/brands/route';
import { Brand } from '@/lib/types';

// Mock the brand service
jest.mock('@/lib/services/brand-service', () => ({
  BrandService: jest.fn().mockImplementation(() => ({
    getBrands: jest.fn(),
  })),
}));

describe('/api/brands', () => {
  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('should return list of brands', async () => {
    const mockBrands: Brand[] = [
      { id: '1', name: 'Wilson', racquet_count: 15 },
      { id: '2', name: 'Babolat', racquet_count: 12 },
      { id: '3', name: 'Head', racquet_count: 8 },
    ];

    const { BrandService } = require('@/lib/services/brand-service');
    const mockGetBrands = jest.fn().mockResolvedValue(mockBrands);
    BrandService.mockImplementation(() => ({ getBrands: mockGetBrands }));

    const request = new NextRequest('http://localhost:3000/api/brands');
    const response = await GET(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.data).toEqual(mockBrands);
    expect(mockGetBrands).toHaveBeenCalledTimes(1);
  });

  it('should handle empty brands list', async () => {
    const { BrandService } = require('@/lib/services/brand-service');
    const mockGetBrands = jest.fn().mockResolvedValue([]);
    BrandService.mockImplementation(() => ({ getBrands: mockGetBrands }));

    const request = new NextRequest('http://localhost:3000/api/brands');
    const response = await GET(request);
    const data = await response.json();

    expect(response.status).toBe(200);
    expect(data.data).toEqual([]);
  });

  it('should handle service errors with proper error response', async () => {
    const { BrandService } = require('@/lib/services/brand-service');
    const mockGetBrands = jest.fn().mockRejectedValue(new Error('Database error'));
    BrandService.mockImplementation(() => ({ getBrands: mockGetBrands }));

    const request = new NextRequest('http://localhost:3000/api/brands');
    const response = await GET(request);
    const data = await response.json();

    expect(response.status).toBe(500);
    expect(data.error).toBe('Database error');
    expect(data.code).toBe('INTERNAL_SERVER_ERROR');
  });
});

