import { NextResponse, NextRequest } from 'next/server';
import { ZodError } from 'zod';
import { logger } from './logger';
import { ValidationError } from './validation';

export interface ApiError {
  error: string;
  message?: string;
  code?: string;
  details?: any;
}

export class AppError extends Error {
  constructor(
    message: string,
    public statusCode: number = 500,
    public code?: string,
    public details?: any
  ) {
    super(message);
    this.name = 'AppError';
  }
}

export class NotFoundError extends AppError {
  constructor(resource: string) {
    super(`${resource} not found`, 404, 'NOT_FOUND');
  }
}

export class BadRequestError extends AppError {
  constructor(message: string, details?: any) {
    super(message, 400, 'BAD_REQUEST', details);
  }
}

export class InternalServerError extends AppError {
  constructor(message: string = 'Internal server error', details?: any) {
    super(message, 500, 'INTERNAL_SERVER_ERROR', details);
  }
}

export function createErrorResponse(
  error: Error,
  method: string,
  endpoint: string
): NextResponse {
  const startTime = Date.now();

  let statusCode = 500;
  let errorResponse: ApiError = {
    error: 'Internal server error',
    message: 'An unexpected error occurred',
  };

  if (error instanceof ValidationError) {
    statusCode = 400;
    errorResponse = {
      error: 'Validation failed',
      message: error.message,
      code: 'VALIDATION_ERROR',
      details: error.issues,
    };
  } else if (error instanceof ZodError) {
    statusCode = 400;
    errorResponse = {
      error: 'Validation failed',
      message: 'Invalid request parameters',
      code: 'VALIDATION_ERROR',
      details: error.issues,
    };
  } else if (error instanceof AppError) {
    statusCode = error.statusCode;
    errorResponse = {
      error: error.message,
      code: error.code,
      details: error.details,
    };
  } else if (error instanceof Error) {
    errorResponse = {
      error: error.message,
      code: 'INTERNAL_SERVER_ERROR',
    };
  }

  // Log the error
  logger.apiError(method, endpoint, error, {
    statusCode,
    errorResponse,
  });

  // In development, include stack trace
  if (process.env.NODE_ENV === 'development' && error.stack) {
    errorResponse.details = {
      ...errorResponse.details,
      stack: error.stack,
    };
  }

  const response = NextResponse.json(errorResponse, { status: statusCode });

  // Log the response
  logger.apiResponse(method, endpoint, statusCode, Date.now() - startTime);

  return response;
}

export function withErrorHandler(
  handler: (request: NextRequest, params?: any) => Promise<NextResponse>
) {
  return async (request: NextRequest, params?: any): Promise<NextResponse> => {
    const method = request.method;
    const endpoint = new URL(request.url).pathname;
    const startTime = Date.now();

    try {
      // Log the request
      logger.apiRequest(method, endpoint);

      const response = await handler(request, params);

      // Log successful response
      logger.apiResponse(
        method,
        endpoint,
        response.status,
        Date.now() - startTime
      );

      return response;
    } catch (error) {
      return createErrorResponse(error as Error, method, endpoint);
    }
  };
}

