'use client';

import { useState, useEffect, lazy, Suspense } from 'react';
import { useRacquetFilters } from '@/lib/hooks/useRacquetFilters';
import { useRacquetComparison } from '@/lib/hooks/useRacquetComparison';
import { Button } from '@/components/ui/Button';
import { Card } from '@/components/ui/Card';
import { LoadingSpinner } from '@/components/ui/LoadingSpinner';
import { SkeletonChart, SkeletonCard } from '@/components/ui/Skeleton';
import { Brand, Racquet } from '@/lib/types';

// Lazy load heavy components for better performance
const RacquetVisualization = lazy(() => 
  import('@/components/visualizations/RacquetVisualization').then(module => ({
    default: module.RacquetVisualization
  }))
);

const RacquetFilters = lazy(() => 
  import('@/components/filters/RacquetFilters').then(module => ({
    default: module.RacquetFilters
  }))
);

const RacquetComparison = lazy(() => 
  import('@/components/comparison/RacquetComparison').then(module => ({
    default: module.RacquetComparison
  }))
);

const RecommendationEngine = lazy(() => 
  import('@/components/recommendations/RecommendationEngine').then(module => ({
    default: module.RecommendationEngine
  }))
);

const AnalyticsDashboard = lazy(() => 
  import('@/components/analytics/AnalyticsDashboard').then(module => ({
    default: module.AnalyticsDashboard
  }))
);

export default function Home() {
  const [racquets, setRacquets] = useState<Racquet[]>([]);
  const [brands, setBrands] = useState<Brand[]>([]);
  const [loading, setLoading] = useState(true);
  const [showVisualization, setShowVisualization] = useState(false);
  const [currentView, setCurrentView] = useState<'visualization' | 'recommendations' | 'analytics'>('visualization');

  useEffect(() => {
    async function loadData() {
      try {
        // Load racquets
        const racquetsResponse = await fetch('/api/racquets');
        let racquetsData: Racquet[] = [];

        if (racquetsResponse.ok) {
          racquetsData = await racquetsResponse.json();
        } else {
          // Fallback to local data if API fails
          const localData = await import('@/data/racquets.json');
          racquetsData = localData.default as RacquetData[];
        }
        setRacquets(racquetsData);

        // Load brands
        try {
          const brandsResponse = await fetch('/api/brands');
          if (brandsResponse.ok) {
            const brandsData = await brandsResponse.json();
            setBrands(brandsData);
          } else {
            // Fallback to local data if API fails
            const localBrands = await import('@/data/brands.json');
            setBrands(localBrands.default as Brand[]);
          }
        } catch (brandsError) {
          console.error('Error loading brands:', brandsError);
          // Fallback to local data
          const localBrands = await import('@/data/brands.json');
          setBrands(localBrands.default as Brand[]);
        }
      } catch (error) {
        console.error('Error loading data:', error);
        // Fallback to local data
        try {
          const localData = await import('@/data/racquets.json');
          setRacquets(localData.default as Racquet[]);
          const localBrands = await import('@/data/brands.json');
          setBrands(localBrands.default as Brand[]);
        } catch (localError) {
          console.error('Error loading local data:', localError);
        }
      } finally {
        setLoading(false);
      }
    }

    loadData();
  }, []);

  // Use the racquet filters hook
  const {
    filters,
    filteredRacquets,
    setFilters,
    resetFilters,
    filterCounts,
    ranges,
  } = useRacquetFilters({
    racquets,
    brands,
    persistToURL: showVisualization,
  });

  // Use the racquet comparison hook
  const comparison = useRacquetComparison();

  if (showVisualization) {
    return (
      <div className="min-h-screen bg-gradient-to-br from-background to-background-secondary">
        {/* Skip Navigation */}
        <a 
          href="#main-content" 
          className="skip-nav"
          tabIndex={0}
        >
          Skip to main content
        </a>
        {/* Navigation Header */}
        <header className="border-b border-border-muted sticky top-0 bg-background/95 backdrop-blur-sm z-50">
          <div className="container mx-auto px-4 py-4">
            <div className="flex items-center justify-between">
              <div className="flex items-center space-x-3">
                <div className="w-8 h-8 rounded-full bg-primary flex items-center justify-center touch-target">
                  <span className="text-white font-bold text-lg" role="img" aria-label="Tennis ball">🎾</span>
                </div>
                <div className="hidden sm:block">
                  <h1 className="text-lg font-bold text-foreground">
                    Tennis Racquet Explorer
                  </h1>
                  <p className="text-xs text-foreground-muted">
                    Interactive Data Exploration
                  </p>
                </div>
                <div className="sm:hidden">
                  <h1 className="text-base font-bold text-foreground">
                    Racquet Explorer
                  </h1>
                </div>
              </div>

              {/* Mobile-friendly navigation */}
              <div className="flex items-center gap-2">
                {/* Tab navigation - responsive */}
                <div className="hidden md:flex bg-gray-100 rounded-lg p-1 mr-4">
                  <button
                    onClick={() => setCurrentView('visualization')}
                    className={`px-3 py-1 text-sm font-medium rounded-md transition-colors touch-target ${
                      currentView === 'visualization' 
                        ? 'bg-white text-gray-900 shadow-sm' 
                        : 'text-gray-600 hover:text-gray-900'
                    }`}
                    aria-pressed={currentView === 'visualization'}
                  >
                    Explore
                  </button>
                  <button
                    onClick={() => setCurrentView('recommendations')}
                    className={`px-3 py-1 text-sm font-medium rounded-md transition-colors touch-target ${
                      currentView === 'recommendations' 
                        ? 'bg-white text-gray-900 shadow-sm' 
                        : 'text-gray-600 hover:text-gray-900'
                    }`}
                    aria-pressed={currentView === 'recommendations'}
                  >
                    Recommendations
                  </button>
                  <button
                    onClick={() => setCurrentView('analytics')}
                    className={`px-3 py-1 text-sm font-medium rounded-md transition-colors touch-target ${
                      currentView === 'analytics' 
                        ? 'bg-white text-gray-900 shadow-sm' 
                        : 'text-gray-600 hover:text-gray-900'
                    }`}
                    aria-pressed={currentView === 'analytics'}
                  >
                    Analytics
                  </button>
                </div>

                {/* Mobile tab dropdown */}
                <div className="md:hidden mr-2">
                  <select
                    value={currentView}
                    onChange={(e) => setCurrentView(e.target.value as 'visualization' | 'recommendations' | 'analytics')}
                    className="text-sm px-2 py-1 rounded border border-border bg-background touch-target"
                    aria-label="Select view"
                  >
                    <option value="visualization">Explore</option>
                    <option value="recommendations">Recommendations</option>
                    <option value="analytics">Analytics</option>
                  </select>
                </div>

                <Button 
                  variant={comparison.isComparing ? "default" : "outline"}
                  onClick={comparison.toggleComparison}
                  className="text-sm touch-target hidden sm:flex"
                  aria-label={comparison.isComparing ? 'Hide comparison panel' : 'Show comparison panel'}
                >
                  <span className="hidden lg:inline">
                    {comparison.isComparing ? 'Hide Comparison' : 'Compare Racquets'}
                  </span>
                  <span className="lg:hidden">
                    Compare
                  </span>
                  {comparison.selectedRacquets.length > 0 && (
                    <span className="ml-2 bg-primary text-white text-xs px-2 py-1 rounded-full">
                      {comparison.selectedRacquets.length}
                    </span>
                  )}
                </Button>

                {/* Mobile compare button */}
                <Button 
                  variant={comparison.isComparing ? "default" : "outline"}
                  onClick={comparison.toggleComparison}
                  className="text-sm touch-target sm:hidden"
                  size="sm"
                  aria-label={comparison.isComparing ? 'Hide comparison' : 'Compare racquets'}
                >
                  📊
                  {comparison.selectedRacquets.length > 0 && (
                    <span className="ml-1 bg-primary text-white text-xs px-1 py-0.5 rounded-full">
                      {comparison.selectedRacquets.length}
                    </span>
                  )}
                </Button>

                <Button 
                  variant="outline" 
                  onClick={() => setShowVisualization(false)}
                  className="text-sm touch-target"
                  aria-label="Go back to home page"
                >
                  <span className="hidden sm:inline">← Back to Home</span>
                  <span className="sm:hidden">←</span>
                </Button>
              </div>
            </div>

            {/* Mobile tab navigation */}
            <div className="md:hidden mt-4 flex bg-gray-100 rounded-lg p-1 tab-nav-mobile">
              <button
                onClick={() => setCurrentView('visualization')}
                className={`flex-1 py-2 text-sm font-medium rounded-md transition-colors touch-target ${
                  currentView === 'visualization' 
                    ? 'bg-white text-gray-900 shadow-sm' 
                    : 'text-gray-600 hover:text-gray-900'
                }`}
                aria-pressed={currentView === 'visualization'}
              >
                🔍 Explore
              </button>
              <button
                onClick={() => setCurrentView('recommendations')}
                className={`flex-1 py-2 text-sm font-medium rounded-md transition-colors touch-target ${
                  currentView === 'recommendations' 
                    ? 'bg-white text-gray-900 shadow-sm' 
                    : 'text-gray-600 hover:text-gray-900'
                }`}
                aria-pressed={currentView === 'recommendations'}
              >
                🎯 Recommend
              </button>
              <button
                onClick={() => setCurrentView('analytics')}
                className={`flex-1 py-2 text-sm font-medium rounded-md transition-colors touch-target ${
                  currentView === 'analytics' 
                    ? 'bg-white text-gray-900 shadow-sm' 
                    : 'text-gray-600 hover:text-gray-900'
                }`}
                aria-pressed={currentView === 'analytics'}
              >
                📈 Analytics
              </button>
            </div>
          </div>
        </header>

        <main id="main-content" className="container mx-auto px-4 py-8" tabIndex={-1}>
          {loading ? (
            <Card className="p-12 text-center">
              <LoadingSpinner size="lg" />
              <p className="mt-4 text-foreground-muted">Loading racquet data...</p>
            </Card>
          ) : (
            <div className="space-y-6">
              {/* Comparison Section */}
              <Suspense fallback={<SkeletonCard />}>
                <RacquetComparison />
              </Suspense>

              {currentView === 'visualization' ? (
                <div className="grid grid-cols-1 lg:grid-cols-4 gap-4 lg:gap-6">
                  {/* Filters Sidebar - Mobile responsive */}
                  <div className="lg:col-span-1 order-2 lg:order-1">
                    <div className="lg:sticky lg:top-24">
                      <Suspense fallback={<SkeletonCard />}>
                        <RacquetFilters
                          brands={brands}
                          selectedBrands={filters.brands}
                          onBrandsChange={(brands) => setFilters({ brands })}

                          weightRange={filters.weight_range}
                          weightLimits={ranges.weight}
                          onWeightChange={(weight_range) => setFilters({ weight_range })}

                          headSizeRange={filters.head_size_range}
                          headSizeLimits={ranges.head_size}
                          onHeadSizeChange={(head_size_range) => setFilters({ head_size_range })}

                          powerRange={filters.power_range}
                          powerLimits={ranges.power}
                          onPowerChange={(power_range) => setFilters({ power_range })}

                          controlRange={filters.control_range}
                          controlLimits={ranges.control}
                          onControlChange={(control_range) => setFilters({ control_range })}

                          comfortRange={filters.comfort_range}
                          comfortLimits={ranges.comfort}
                          onComfortChange={(comfort_range) => setFilters({ comfort_range })}

                          searchQuery={filters.search_query}
                          onSearchChange={(search_query) => setFilters({ search_query })}

                          onReset={resetFilters}

                          totalCount={filterCounts.total}
                          filteredCount={filterCounts.filtered}
                        />
                      </Suspense>
                    </div>
                  </div>

                  {/* Visualization - Mobile responsive */}
                  <div className="lg:col-span-3 order-1 lg:order-2">
                    <div className="h-96 lg:h-[600px] xl:h-[700px]">
                      <Suspense fallback={<SkeletonChart />}>
                        <RacquetVisualization 
                          racquets={filteredRacquets} 
                          onRacquetSelect={comparison.addRacquet}
                          selectedRacquets={comparison.selectedRacquets}
                          canAddMore={comparison.canAddMore}
                        />
                      </Suspense>
                    </div>
                  </div>
                </div>
              ) : currentView === 'recommendations' ? (
                /* Recommendations Section */
                <Suspense fallback={<SkeletonChart />}>
                  <RecommendationEngine
                    racquets={filteredRacquets}
                    onCompareRacquet={comparison.addRacquet}
                    onViewRacquetDetails={(racquet) => {
                      // Switch to visualization view and highlight the racquet
                      setCurrentView('visualization');
                      // Could add logic to highlight specific racquet in visualization
                      console.log('Viewing racquet details:', racquet.model);
                    }}
                  />
                </Suspense>
              ) : (
                /* Analytics Section */
                <Suspense fallback={<SkeletonChart />}>
                  <AnalyticsDashboard
                    racquets={filteredRacquets}
                    className="min-h-96"
                  />
                </Suspense>
              )}
            </div>
          )}
        </main>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-gradient-to-br from-background to-background-secondary relative overflow-hidden">
      {/* Skip Navigation */}
      <a 
        href="#main-content-home" 
        className="skip-nav"
        tabIndex={0}
      >
        Skip to main content
      </a>
      {/* Tennis Ball Background Animation */}
      <div className="absolute inset-0 pointer-events-none">
        <div className="absolute top-20 left-10 w-4 h-4 bg-accent rounded-full animate-bounce opacity-20" style={{ animationDelay: '0s', animationDuration: '3s' }}></div>
        <div className="absolute top-40 right-20 w-3 h-3 bg-accent rounded-full animate-bounce opacity-15" style={{ animationDelay: '1s', animationDuration: '4s' }}></div>
        <div className="absolute bottom-32 left-1/4 w-2 h-2 bg-accent rounded-full animate-bounce opacity-10" style={{ animationDelay: '2s', animationDuration: '5s' }}></div>
        <div className="absolute bottom-20 right-1/3 w-5 h-5 bg-accent rounded-full animate-bounce opacity-25" style={{ animationDelay: '0.5s', animationDuration: '3.5s' }}></div>
      </div>

      {/* Header */}
      <header className="border-b border-border-muted relative z-10">
        <div className="container mx-auto px-4 py-6">
          <div className="flex items-center justify-between">
            <div className="flex items-center space-x-3">
              <div className="w-8 h-8 rounded-full bg-primary flex items-center justify-center shadow-lg">
                <span className="text-white font-bold text-lg">🎾</span>
              </div>
              <div>
                <h1 className="text-xl font-bold text-foreground">
                  Tennis Racquet Explorer
                </h1>
                <p className="text-sm text-foreground-muted">
                  Discover the intersection of feel and physics
                </p>
              </div>
            </div>
          </div>
        </div>
      </header>

      {/* Hero Section */}
      <main id="main-content-home" className="container mx-auto px-4 py-12 relative z-10" tabIndex={-1}>
        <div className="max-w-4xl mx-auto text-center">
          <h2 className="text-4xl md:text-6xl font-bold text-foreground mb-6">
            Find Your Perfect
            <span className="text-primary block bg-gradient-to-r from-primary to-primary-light bg-clip-text text-transparent">
              Tennis Racquet
            </span>
          </h2>
          <p className="text-xl text-foreground-muted mb-8 max-w-2xl mx-auto">
            Explore over 100 racquets through interactive visualizations that
            connect physical specifications to player performance ratings.
          </p>

          {/* Interactive Demo Button */}
          <div className="mb-12">
            <Button 
              size="lg" 
              onClick={() => setShowVisualization(true)}
              className="bg-primary hover:bg-primary-dark text-white px-8 py-4 text-lg font-semibold shadow-lg hover:shadow-xl transform hover:scale-105 transition-all duration-200"
              disabled={loading}
            >
              {loading ? (
                <>
                  <LoadingSpinner size="sm" className="mr-2" />
                  Loading Data...
                </>
              ) : (
                <>
                  🎾 Explore Racquets Now
                </>
              )}
            </Button>
            <p className="text-sm text-foreground-muted mt-3">
              Interactive data visualization • No registration required
            </p>
          </div>

          {/* Features Grid - Mobile responsive */}
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 lg:gap-6 mt-12 features-grid-mobile">
            <div className="bg-white/70 backdrop-blur-sm rounded-lg p-4 lg:p-6 border border-border-muted shadow-lg hover:shadow-xl transition-shadow tennis-card-hover">
              <div className="w-10 h-10 lg:w-12 lg:h-12 bg-gradient-to-br from-primary to-primary-light rounded-lg flex items-center justify-center mx-auto mb-3 lg:mb-4 shadow-md">
                <span className="text-xl lg:text-2xl" role="img" aria-label="Data visualization">📊</span>
              </div>
              <h3 className="text-base lg:text-lg font-semibold mb-2">Data Visualization</h3>
              <p className="text-sm lg:text-base text-foreground-muted">
                Interactive scatter plots showing racquet relationships and performance characteristics
              </p>
            </div>

            <div className="bg-white/70 backdrop-blur-sm rounded-lg p-4 lg:p-6 border border-border-muted shadow-lg hover:shadow-xl transition-shadow tennis-card-hover">
              <div className="w-10 h-10 lg:w-12 lg:h-12 bg-gradient-to-br from-accent to-accent-dark rounded-lg flex items-center justify-center mx-auto mb-3 lg:mb-4 shadow-md">
                <span className="text-xl lg:text-2xl" role="img" aria-label="Smart recommendations">🎯</span>
              </div>
              <h3 className="text-base lg:text-lg font-semibold mb-2">Smart Recommendations</h3>
              <p className="text-sm lg:text-base text-foreground-muted">
                AI-powered suggestions based on playing style and performance preferences
              </p>
            </div>

            <div className="bg-white/70 backdrop-blur-sm rounded-lg p-4 lg:p-6 border border-border-muted shadow-lg hover:shadow-xl transition-shadow tennis-card-hover">
              <div className="w-10 h-10 lg:w-12 lg:h-12 bg-gradient-to-br from-primary to-primary-light rounded-lg flex items-center justify-center mx-auto mb-3 lg:mb-4 shadow-md">
                <span className="text-xl lg:text-2xl" role="img" aria-label="Detailed comparisons">⚖️</span>
              </div>
              <h3 className="text-base lg:text-lg font-semibold mb-2">Detailed Comparisons</h3>
              <p className="text-sm lg:text-base text-foreground-muted">
                Side-by-side analysis with radar charts and performance trade-offs
              </p>
            </div>

            <div className="bg-white/70 backdrop-blur-sm rounded-lg p-4 lg:p-6 border border-border-muted shadow-lg hover:shadow-xl transition-shadow tennis-card-hover">
              <div className="w-10 h-10 lg:w-12 lg:h-12 bg-gradient-to-br from-purple-500 to-purple-600 rounded-lg flex items-center justify-center mx-auto mb-3 lg:mb-4 shadow-md">
                <span className="text-xl lg:text-2xl" role="img" aria-label="Performance analytics">📈</span>
              </div>
              <h3 className="text-base lg:text-lg font-semibold mb-2">Performance Analytics</h3>
              <p className="text-sm lg:text-base text-foreground-muted">
                Statistical insights, brand analysis, and data quality metrics
              </p>
            </div>
          </div>

          {/* Quick Stats - Mobile responsive */}
          {!loading && racquets.length > 0 && (
            <div className="mt-12 lg:mt-16 p-4 lg:p-6 bg-primary/5 rounded-lg border border-primary/20 backdrop-blur-sm">
              <h3 className="text-base lg:text-lg font-semibold mb-4 text-center">Dataset Overview</h3>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4 stats-grid-mobile">
                <div className="text-center p-3 bg-white/50 rounded-lg">
                  <div className="text-2xl lg:text-3xl font-bold text-primary">{racquets.length}</div>
                  <div className="text-xs lg:text-sm text-foreground-muted">Racquets</div>
                </div>
                <div className="text-center p-3 bg-white/50 rounded-lg">
                  <div className="text-2xl lg:text-3xl font-bold text-primary">
                    {new Set(racquets.map(r => r.brand)).size}
                  </div>
                  <div className="text-xs lg:text-sm text-foreground-muted">Brands</div>
                </div>
                <div className="text-center p-3 bg-white/50 rounded-lg">
                  <div className="text-2xl lg:text-3xl font-bold text-primary">
                    {Math.round(racquets.reduce((sum, r) => sum + r.overall_avg, 0) / racquets.length * 10) / 10}
                  </div>
                  <div className="text-xs lg:text-sm text-foreground-muted">Avg Rating</div>
                </div>
                <div className="text-center p-3 bg-white/50 rounded-lg">
                  <div className="text-2xl lg:text-3xl font-bold text-primary">
                    {Math.round(racquets.reduce((sum, r) => sum + r.weight_oz, 0) / racquets.length * 10) / 10}
                  </div>
                  <div className="text-xs lg:text-sm text-foreground-muted">Avg Weight (oz)</div>
                </div>
              </div>
            </div>
          )}

          {/* Development Progress */}
          <div className="mt-16 p-6 bg-primary/5 rounded-lg border border-primary/20 backdrop-blur-sm">
            <h3 className="text-lg font-semibold mb-4">Development Progress</h3>
            <div className="space-y-3">
              <div className="flex items-center justify-between">
                <span>Project Setup & Design System</span>
                <div className="flex items-center space-x-2">
                  <div className="w-32 bg-border rounded-full h-2">
                    <div className="bg-primary h-2 rounded-full w-full"></div>
                  </div>
                  <span className="text-sm text-foreground-muted">100%</span>
                </div>
              </div>
              <div className="flex items-center justify-between">
                <span>2D Data Visualization</span>
                <div className="flex items-center space-x-2">
                  <div className="w-32 bg-border rounded-full h-2">
                    <div className="bg-primary h-2 rounded-full w-full"></div>
                  </div>
                  <span className="text-sm text-foreground-muted">100%</span>
                </div>
              </div>
              <div className="flex items-center justify-between">
                <span>Tennis-Themed Design</span>
                <div className="flex items-center space-x-2">
                  <div className="w-32 bg-border rounded-full h-2">
                    <div className="bg-primary h-2 rounded-full w-full"></div>
                  </div>
                  <span className="text-sm text-foreground-muted">100%</span>
                </div>
              </div>
              <div className="flex items-center justify-between">
                <span>Database Schema & API</span>
                <div className="flex items-center space-x-2">
                  <div className="w-32 bg-border rounded-full h-2">
                    <div className="bg-warning h-2 rounded-full w-1/4"></div>
                  </div>
                  <span className="text-sm text-foreground-muted">Pending</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </main>

      {/* Footer */}
      <footer className="border-t border-border-muted mt-16 relative z-10">
        <div className="container mx-auto px-4 py-8">
          <div className="text-center text-foreground-muted">
            <p>Built with Next.js, TypeScript, D3.js, and Tailwind CSS</p>
            <p className="mt-2">Sprint 1: Foundation & Core Architecture • Sprint 2: Data Visualization</p>
          </div>
        </div>
      </footer>
    </div>
  );
}

