      {/* Tab Content */}
      <div className="min-h-96">
        {activeTab === 'performance' && renderPerformanceTab()}
        {activeTab === 'physical' && renderPhysicalTab()}
        {activeTab === 'brands' && renderBrandsTab()}
        {activeTab === 'quality' && renderQualityTab()}
      </div>
    </div>
  );
};

