import { NextRequest, NextResponse } from 'next/server';
import { ApiResponse, RacquetWithReviews } from '@/lib/types';
import { RacquetService } from '@/lib/services/racquet-service';
import { validateRacquetId } from '@/lib/validation';
import { withErrorHandler, NotFoundError } from '@/lib/error-handler';

export const GET = withErrorHandler(async (
  request: NextRequest,
  { params }: { params: Promise<{ id: string }> }
) => {
  const { id } = await params;

  // Validate racquet ID
  const validId = validateRacquetId(id);

  const racquetService = new RacquetService();
  const racquet = await racquetService.getRacquetById(validId);

  if (!racquet) {
    throw new NotFoundError('Racquet');
  }

  const response: ApiResponse<RacquetWithReviews> = {
    data: racquet,
  };

  return NextResponse.json(response);
});

