function CameraController({ 
  position = [10, 10, 10], 
  onCameraChange 
}: { 
  position?: [number, number, number];
  onCameraChange?: (position: THREE.Vector3, target: THREE.Vector3) => void;
}) {
  const controlsRef = useRef<THREE.Object3D>();
  const { camera } = useThree();

  useEffect(() => {
    if (camera) {
      camera.position.set(...position);
      camera.lookAt(0, 0, 0);
    }
  }, [camera, position]);

  useFrame(() => {
    if (controlsRef.current && onCameraChange) {
      const controls = controlsRef.current as THREE.Object3D & { target?: THREE.Vector3 };
      onCameraChange(camera.position, controls.target || new THREE.Vector3(0, 0, 0));
    }
  });

  return (
    <OrbitControls
      ref={controlsRef}
      enablePan={true}
      enableZoom={true}
      enableRotate={true}
      dampingFactor={0.05}
      enableDamping={true}
      maxDistance={50}
      minDistance={5}
      maxPolarAngle={Math.PI}
      minPolarAngle={0}
      autoRotate={false}
      autoRotateSpeed={0.5}
      target={[0, 0, 0]}
    />
  );
}

function Lighting() {
  return (
    <>
      <ambientLight intensity={0.4} />
      <directionalLight
        position={[10, 10, 10]}
        intensity={1}
        castShadow
        shadow-mapSize-width={2048}
        shadow-mapSize-height={2048}
        shadow-camera-far={50}
        shadow-camera-left={-10}
        shadow-camera-right={10}
        shadow-camera-top={10}
        shadow-camera-bottom={-10}
      />
      <directionalLight
        position={[-10, -10, -10]}
